from Crypto.Cipher import AES
from Crypto.Random import get_random_bytes
from base64 import b64encode, b64decode
import os

def encrypt(data):
    key = os.urandom(32)  # Generate a random 256-bit encryption key
    cipher = AES.new(key, AES.MODE_EAX)
    nonce = cipher.nonce
    ciphertext = cipher.encrypt(data)
    tag = cipher.tag
    return (nonce + b64encode(ciphertext) + b64encode(tag)).decode('utf-8')